import{_ as a,o as i,c as s,aa as l}from"./chunks/framework.GPvTQ_Wl.js";const u=JSON.parse('{"title":"Build from source","description":"","frontmatter":{},"headers":[],"relativePath":"guide/building-from-source.md","filePath":"guide/building-from-source.md","lastUpdated":1775689403000}'),t={name:"guide/building-from-source.md"};function o(n,e,d,r,c,p){return i(),s("div",null,[...e[0]||(e[0]=[l(`<h1 id="build-from-source" tabindex="-1">Build from source <a class="header-anchor" href="#build-from-source" aria-label="Permalink to &quot;Build from source&quot;">​</a></h1><p>This page explains how to use the project <code>Makefile</code> to set up dependencies, build the mod package, and run/install it for Rome II or Attila.</p><h2 id="windows-setup-step-by-step" tabindex="-1">Windows Setup (Step by Step) <a class="header-anchor" href="#windows-setup-step-by-step" aria-label="Permalink to &quot;Windows Setup (Step by Step)&quot;">​</a></h2><p>The build pipeline is designed for Windows with GNU Make running in Git Bash.</p><p>Important: run every <code>make</code> command in <strong>Git Bash</strong>.<br> Do not run <code>make</code> from CMD or PowerShell.</p><h3 id="_1-install-git-for-windows" tabindex="-1">1) Install Git for Windows <a class="header-anchor" href="#_1-install-git-for-windows" aria-label="Permalink to &quot;1) Install Git for Windows&quot;">​</a></h3><p>Download and run:</p><ul><li><a href="https://github.com/git-for-windows/git/releases/download/v2.53.0.windows.2/Git-2.53.0.2-64-bit.exe" target="_blank" rel="noreferrer">Git for Windows 64-bit installer</a></li></ul><p>After install, open <strong>Git Bash</strong> and verify:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><h3 id="_2-install-gnu-make" tabindex="-1">2) Install GNU Make <a class="header-anchor" href="#_2-install-gnu-make" aria-label="Permalink to &quot;2) Install GNU Make&quot;">​</a></h3><p>Download and run:</p><ul><li><a href="https://sourceforge.net/projects/gnuwin32/files/make/3.81/make-3.81.exe/download" target="_blank" rel="noreferrer">GNU Make 3.81 installer</a></li></ul><p>During installation, ensure <code>make.exe</code> is added to your <code>PATH</code> environment variable (or add it manually after install).</p><p>Then in <strong>Git Bash</strong>, verify:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><h3 id="_3-confirm-powershell-is-available" tabindex="-1">3) Confirm PowerShell is available <a class="header-anchor" href="#_3-confirm-powershell-is-available" aria-label="Permalink to &quot;3) Confirm PowerShell is available&quot;">​</a></h3><p>Some <code>Makefile</code> targets use PowerShell. Verify from either Git Bash or PowerShell:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">powershell</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Command</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$PSVersionTable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.PSVersion&quot;</span></span></code></pre></div><h3 id="_4-clone-the-repository" tabindex="-1">4) Clone the repository <a class="header-anchor" href="#_4-clone-the-repository" aria-label="Permalink to &quot;4) Clone the repository&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/bukowa/ConsulScriptum.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ConsulScriptum</span></span></code></pre></div><h3 id="_5-bootstrap-project-dependencies" tabindex="-1">5) Bootstrap project dependencies <a class="header-anchor" href="#_5-bootstrap-project-dependencies" aria-label="Permalink to &quot;5) Bootstrap project dependencies&quot;">​</a></h3><p>Run from <strong>Git Bash</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>This prepares <code>./.deps</code> and initializes build directories.</p><h2 id="what-make-setup-installs" tabindex="-1">What <code>make setup</code> installs <a class="header-anchor" href="#what-make-setup-installs" aria-label="Permalink to &quot;What \`make setup\` installs&quot;">​</a></h2><p>The <code>setup</code> target downloads and configures these tool dependencies into <code>./.deps</code>:</p><ul><li><code>rpfm_cli</code> (pack creation and schema operations)</li><li><code>rpfm_schema</code></li><li><code>etwng</code> (<code>xml2ui</code>, <code>ui2xml</code>)</li><li><code>7zip</code></li><li><code>Ruby</code> + required gems for etwng</li><li><code>ldoc</code> (for Lua docs generation)</li></ul><h2 id="core-variables" tabindex="-1">Core Variables <a class="header-anchor" href="#core-variables" aria-label="Permalink to &quot;Core Variables&quot;">​</a></h2><p>Useful variables exposed by the <code>Makefile</code>:</p><ul><li><code>GAME</code>: <code>Attila</code> (default) or <code>Rome2</code></li><li><code>DEV</code>: <code>1</code> enables extra dev UI target for Attila (<code>layout.xml</code>)</li><li><code>SAVE</code>: optional save name used by install/run targets</li></ul><p>Examples:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GAME=Attila</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GAME=Rome2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> DEV=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre></div><h2 id="build-workflow" tabindex="-1">Build Workflow <a class="header-anchor" href="#build-workflow" aria-label="Permalink to &quot;Build Workflow&quot;">​</a></h2><p>Run all commands in this section from <strong>Git Bash</strong>.</p><h3 id="_1-build-package" tabindex="-1">1) Build package <a class="header-anchor" href="#_1-build-package" aria-label="Permalink to &quot;1) Build package&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GAME=Attila</span></span></code></pre></div><p>or:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GAME=Rome2</span></span></code></pre></div><p>This creates <code>consulscriptum.pack</code> from files staged in <code>./build</code>.</p><h3 id="_2-install-and-run" tabindex="-1">2) Install and run <a class="header-anchor" href="#_2-install-and-run" aria-label="Permalink to &quot;2) Install and run&quot;">​</a></h3><p>Common targets:</p><ul><li><code>make GAME=Attila install-alone</code></li><li><code>make GAME=Attila install-steam</code></li><li><code>make GAME=Attila run-alone</code></li><li><code>make GAME=Attila run-steam</code></li><li><code>make GAME=Attila run-alone-dei</code></li></ul><p>Short aliases:</p><ul><li><code>make alone</code> -&gt; <code>run-alone</code></li><li><code>make steam</code> -&gt; <code>run-steam</code></li></ul><h2 id="useful-targets" tabindex="-1">Useful Targets <a class="header-anchor" href="#useful-targets" aria-label="Permalink to &quot;Useful Targets&quot;">​</a></h2><ul><li><code>clean</code>: remove <code>build</code> artifacts and built pack</li><li><code>kill-game</code>: force close currently running game process</li><li><code>generate-docs</code>: generate Lua API docs via <code>ldoc</code></li><li><code>insert-consul-entry</code>: add a new Consul entry to the relevant UI XML (game-aware)</li></ul><h2 id="game-specific-build-notes" tabindex="-1">Game-Specific Build Notes <a class="header-anchor" href="#game-specific-build-notes" aria-label="Permalink to &quot;Game-Specific Build Notes&quot;">​</a></h2><ul><li><p><strong>Attila</strong></p><ul><li>Uses <code>src/ui/common ui/consul.xml</code></li><li>Uses <code>src/lua_scripts/all_scripted_attila.lua</code></li></ul></li><li><p><strong>Rome2</strong></p><ul><li>Uses <code>src/ui/common ui/menu_bar.xml</code> and <code>src/ui/frontend ui/sp_frame.xml</code></li><li>Uses <code>src/lua_scripts/all_scripted_rome2.lua</code></li></ul></li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><ul><li>If <code>make</code> commands fail on Windows, run from <strong>Git Bash</strong> (not plain CMD).</li><li>If setup tools are missing/corrupted, run:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clean</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><ul><li>If XML conversion commands fail, confirm <code>setup-etwng</code> succeeded and binaries exist under <code>./.deps/etwng/ui/bin/</code>.</li></ul>`,53)])])}const k=a(t,[["render",o]]);export{u as __pageData,k as default};
